import type { LessonContent } from "./types";

const epidemiologyBasics: LessonContent = { title: "Epidemiology Fundamentals", cellular: { title: "Population Health Science", content: "Epidemiology is the study of the distribution and determinants of disease, injury, and other health-related events in populations, and the application of this knowledge to control health problems. It is the foundational science of public health. Key measures include incidence (number of NEW cases in a population over a specified time period), prevalence (total number of EXISTING cases at a given point in time or period), morbidity rate (proportion of population affected by disease), and mortality rate (proportion of deaths in a population). The epidemiological triad model describes disease causation through three interacting factors: the agent (biological, chemical, physical, or nutritional factor that causes disease), the host (the person affected, with factors like age, genetics, immunity, and behavior influencing susceptibility), and the environment (external conditions that promote exposure, including physical, biological, and socioeconomic factors). When these three factors are in balance, health is maintained; disease occurs when the balance is disrupted. John Snow is considered the father of epidemiology for his investigation of the 1854 London cholera outbreak, which demonstrated the waterborne transmission of cholera before the germ theory was established." },
  signs: { left: ["Incidence: NEW cases per population per time period", "Prevalence: ALL existing cases at a point in time", "Morbidity: illness rates in a population", "Mortality: death rates in a population", "Attack rate: proportion of exposed who become ill in an outbreak"], right: ["Epidemic: disease occurrence exceeding normal expectation", "Pandemic: epidemic spread across multiple countries/continents", "Endemic: constant presence of disease in a population", "Outbreak: localized increase in disease occurrence", "Surveillance failure: delayed detection of disease trends"] },
  medications: [],
  pearls: ["Incidence measures NEW cases; prevalence measures ALL cases (new + existing)", "Prevalence = Incidence × Duration of disease", "Attack rate is used in outbreak investigations: (ill/exposed) × 100", "Relative risk compares disease rates in exposed vs. unexposed groups", "Odds ratio is used in case-control studies; relative risk in cohort studies", "John Snow's cholera investigation: removed the Broad Street pump handle — classic public health intervention", "Descriptive epidemiology answers WHO, WHAT, WHEN, WHERE; analytic epidemiology answers WHY/HOW"],
  quiz: [{ question: "What is the difference between incidence and prevalence?", options: ["They are the same measure", "Incidence measures new cases; prevalence measures all existing cases", "Prevalence measures new cases; incidence measures all existing cases", "Incidence measures deaths; prevalence measures births"], correct: 1, rationale: "Incidence measures the rate of NEW cases of disease in a population over a defined time period. Prevalence measures the total number of EXISTING cases (both new and previously diagnosed) at a specific point in time or period." }, { question: "During a foodborne illness outbreak at a picnic, 45 of 120 attendees became ill. What is the attack rate?", options: ["3.75%", "37.5%", "45%", "26.7%"], correct: 1, rationale: "Attack rate = (number ill / number exposed) × 100 = (45/120) × 100 = 37.5%. The attack rate measures the proportion of exposed individuals who develop the disease during an outbreak." }] };

const communicableDiseaseManagement: LessonContent = { title: "Communicable Disease Management", cellular: { title: "Infectious Disease Transmission and Control", content: "Communicable (infectious) diseases are caused by pathogenic microorganisms (bacteria, viruses, parasites, fungi) that can be transmitted from one person or animal to another. The chain of infection describes the six links required for disease transmission: infectious agent (the pathogen), reservoir (where the organism lives and multiplies — human, animal, or environmental), portal of exit (how the organism leaves the reservoir — respiratory, GI, genitourinary, skin), mode of transmission (how the organism is transferred — direct contact, droplet, airborne, vehicle-borne, vector-borne), portal of entry (how the organism enters the new host — same routes as exit), and susceptible host (a person lacking sufficient immunity or defense). Breaking ANY link in the chain prevents transmission. Modes of transmission include: contact (direct person-to-person or indirect through fomites), droplet (large respiratory particles traveling <3-6 feet — influenza, pertussis), airborne (small particles remaining suspended in air — TB, measles, varicella), vehicle (contaminated food, water, blood), and vector (insects — malaria, dengue, Lyme disease). Public health nurses play critical roles in surveillance, case investigation, contact tracing, outbreak management, immunization, health education, and policy implementation." },
  signs: { left: ["Chain of infection: agent, reservoir, portal of exit, transmission, portal of entry, susceptible host", "Contact precautions: gown + gloves (MRSA, C. diff, scabies)", "Droplet precautions: surgical mask within 3-6 feet (influenza, pertussis, meningococcal)", "Airborne precautions: N95 respirator + negative pressure room (TB, measles, varicella, COVID-19)", "Standard precautions apply to ALL patients regardless of diagnosis"], right: ["Outbreaks requiring immediate public health notification", "Drug-resistant organisms: MRSA, VRE, CRE, MDR-TB", "Emerging infectious diseases: novel pathogens with pandemic potential", "Healthcare-associated infections (HAIs): preventable nosocomial transmission", "Bioterrorism agents: anthrax, smallpox, plague, botulism"] },
  medications: [{ name: "Oseltamivir (Tamiflu)", type: "Neuraminidase inhibitor", action: "Inhibits influenza viral replication; reduces symptom duration if started within 48 hours", sideEffects: "Nausea, vomiting, headache", contra: "Severe renal impairment (adjust dose)", pearl: "Most effective when started within 48 hours of symptom onset; also used for post-exposure prophylaxis in high-risk contacts" }, { name: "Isoniazid (INH)", type: "Antitubercular", action: "Inhibits mycolic acid synthesis in Mycobacterium tuberculosis cell wall", sideEffects: "Hepatotoxicity, peripheral neuropathy", contra: "Active hepatic disease, prior INH hepatotoxicity", pearl: "9 months of INH for latent TB infection; always give with pyridoxine (B6) to prevent peripheral neuropathy; monthly LFTs required" }],
  pearls: ["Breaking ANY link in the chain of infection prevents disease transmission", "Standard precautions for ALL patients: hand hygiene, PPE for body fluid exposure, safe sharps disposal", "Airborne diseases (TB, measles, varicella): N95 respirator + negative pressure isolation room", "Droplet diseases (influenza, pertussis): surgical mask within 3-6 feet; no negative pressure needed", "Contact diseases (MRSA, C. diff, scabies): gown + gloves for patient contact and environment", "Reportable diseases must be reported to public health within specified timeframes (varies by jurisdiction)", "Contact tracing is the systematic identification and follow-up of persons who may have been exposed"],
  quiz: [{ question: "A patient is diagnosed with active pulmonary tuberculosis. What type of isolation is required?", options: ["Contact precautions only", "Droplet precautions", "Airborne precautions with N95 respirator and negative pressure room", "Standard precautions only"], correct: 2, rationale: "Pulmonary TB is transmitted via airborne particles (droplet nuclei <5 microns) that can remain suspended in air for hours. Airborne precautions require an N95 respirator, negative pressure isolation room, and the door must remain closed." }, { question: "Which nursing action breaks the 'mode of transmission' link in the chain of infection?", options: ["Immunizing susceptible individuals", "Hand hygiene between patient contacts", "Isolating the infected patient", "Treating the disease with antibiotics"], correct: 1, rationale: "Hand hygiene breaks the mode of transmission link by preventing the transfer of organisms from one surface to another. It is the single most important infection prevention measure." }] };

const immunizationPrograms: LessonContent = { title: "Immunization Programs and Vaccine Science", cellular: { title: "Vaccine Immunology", content: "Immunization is one of the most cost-effective public health interventions, preventing an estimated 2-3 million deaths annually worldwide. Vaccines work by stimulating the adaptive immune system to produce a protective immune response without causing disease. Active immunization introduces antigens (killed/inactivated organisms, live attenuated organisms, toxoids, or recombinant proteins) that stimulate the body to produce its own antibodies and memory cells, providing long-lasting protection. Passive immunization provides pre-formed antibodies (immunoglobulins) for immediate but temporary protection. Vaccine types include: live attenuated (MMR, varicella, rotavirus — contraindicated in pregnancy and immunocompromised), inactivated/killed (influenza injection, hepatitis A, IPV), toxoid (tetanus, diphtheria — inactivated toxins), subunit/conjugate (Hib, pneumococcal, hepatitis B), and mRNA (COVID-19 vaccines — instruct cells to produce antigen protein). Herd immunity occurs when a sufficient proportion of the population is immune to reduce disease transmission, protecting those who cannot be vaccinated (infants, immunocompromised, pregnant women). The threshold for herd immunity varies by disease: measles requires ~95% vaccination coverage due to its extreme contagiousness." },
  signs: { left: ["Active immunity: body produces own antibodies (vaccination, natural infection) — long-lasting", "Passive immunity: pre-formed antibodies given (IVIG, maternal antibodies) — temporary", "Herd immunity: sufficient population coverage to interrupt disease transmission", "Childhood immunization schedule: systematic vaccination from birth through adolescence", "Cold chain maintenance: proper vaccine storage (2-8°C for most) essential for potency"], right: ["Vaccine-preventable disease outbreaks from declining vaccination rates", "Anaphylaxis: rare but life-threatening allergic reaction requiring epinephrine", "Vaccine hesitancy: misinformation, fear, and distrust reducing coverage", "Live vaccine risk in immunocompromised: can cause actual disease", "Cold chain failure: vaccines lose potency if temperature is not maintained"] },
  medications: [{ name: "MMR Vaccine", type: "Live attenuated virus vaccine", action: "Provides active immunity against measles, mumps, and rubella", sideEffects: "Fever, rash, joint pain (rubella component), rare febrile seizures", contra: "Pregnancy, severe immunodeficiency, anaphylaxis to prior dose or neomycin", pearl: "Two doses: 12-15 months and 4-6 years; contraindicated in pregnancy — wait 4 weeks after vaccination before conceiving; NO link to autism (thoroughly debunked)" }, { name: "Tdap Vaccine", type: "Toxoid + inactivated vaccine", action: "Provides immunity against tetanus, diphtheria, and pertussis", sideEffects: "Injection site pain, low-grade fever, headache", contra: "History of encephalopathy within 7 days of prior pertussis vaccine", pearl: "Give in EVERY pregnancy at 27-36 weeks to provide passive immunity to the newborn against pertussis; also given as wound prophylaxis if >5 years since last tetanus dose" }],
  pearls: ["Vaccines do NOT cause autism — this has been thoroughly debunked by overwhelming scientific evidence", "Live vaccines (MMR, varicella, rotavirus) are CONTRAINDICATED in pregnancy and severe immunodeficiency", "Tdap in pregnancy at 27-36 weeks: passive immunity protects the newborn against pertussis in the first months of life", "Hep B vaccine at birth; complete series by 6-18 months", "Influenza vaccine: recommended for EVERYONE ≥6 months, especially pregnant women and immunocompromised", "Vaccine adverse events: report to VAERS (Vaccine Adverse Event Reporting System)", "Address vaccine hesitancy with empathy, evidence-based information, and motivational interviewing", "Contraindication vs. precaution: contraindication = do NOT give; precaution = weigh risk vs. benefit"],
  quiz: [{ question: "A pregnant patient asks about the MMR vaccine. What is the correct response?", options: ["Safe to give in any trimester", "Contraindicated in pregnancy — it is a live vaccine", "Give only in the third trimester", "Give only the rubella component"], correct: 1, rationale: "MMR is a live attenuated vaccine and is contraindicated in pregnancy due to the theoretical risk of fetal infection. Women should wait at least 4 weeks after MMR vaccination before becoming pregnant." }, { question: "Why is the Tdap vaccine recommended during every pregnancy at 27-36 weeks?", options: ["To protect the mother from tetanus during delivery", "To provide passive antibody transfer to the newborn for pertussis protection", "To prevent group B strep infection", "It is only recommended in the first pregnancy"], correct: 1, rationale: "Tdap at 27-36 weeks maximizes maternal antibody production and transplacental transfer of pertussis antibodies to the fetus, providing passive immunity during the first months of life when the infant is too young to be vaccinated." }] };

const healthPromotion: LessonContent = { title: "Health Promotion and Disease Prevention", cellular: { title: "Prevention Levels and Health Behavior Models", content: "Health promotion is the process of enabling people to increase control over and improve their health. It encompasses individual behavior change, community empowerment, and policy advocacy. The three levels of prevention provide a framework for public health interventions: Primary prevention prevents disease BEFORE it occurs (immunization, health education, exercise promotion, seatbelt use, water fluoridation, nutrition counseling). Secondary prevention detects disease EARLY through screening and prompt treatment to halt progression and minimize complications (mammography, colonoscopy, blood pressure screening, diabetes screening, depression screening, newborn metabolic screening). Tertiary prevention manages EXISTING disease to prevent complications, restore function, and maximize quality of life (cardiac rehabilitation, diabetes management programs, physical therapy, palliative care). Health behavior models guide intervention design: the Health Belief Model posits that health behavior is influenced by perceived susceptibility, severity, benefits, barriers, cues to action, and self-efficacy. The Transtheoretical Model (Stages of Change) describes five stages: precontemplation, contemplation, preparation, action, and maintenance. Motivational interviewing is an evidence-based counseling approach that supports behavior change through empathy, developing discrepancy, rolling with resistance, and supporting self-efficacy." },
  signs: { left: ["Primary prevention: immunization, health education, safety measures, nutrition counseling", "Secondary prevention: screening, early detection, prompt treatment", "Tertiary prevention: rehabilitation, chronic disease management, palliative care", "Health Belief Model: susceptibility, severity, benefits, barriers, cues, self-efficacy", "Stages of Change: precontemplation → contemplation → preparation → action → maintenance"], right: ["Health disparities: unequal disease burden across populations", "Health literacy: inadequate understanding impairs self-management", "Non-adherence to preventive recommendations", "Missed screening opportunities leading to late diagnosis", "Socioeconomic barriers to healthy behaviors"] },
  medications: [],
  pearls: ["Primary prevention = BEFORE disease; secondary = EARLY detection; tertiary = MANAGING existing disease", "Immunization is the most cost-effective primary prevention intervention", "Screening guidelines change based on evidence: know current recommendations for major cancers, diabetes, hypertension", "Meet patients where they are: assess stage of change before recommending behavior change", "Motivational interviewing > lecturing: explore ambivalence, support autonomy, build self-efficacy", "Health literacy: use plain language, teach-back method, visual aids, and culturally appropriate materials", "Social determinants of health (income, education, housing, food access) are more powerful predictors of health than medical care", "Healthy People objectives provide national health targets and benchmarks for improvement"],
  quiz: [{ question: "A community nurse organizes a blood pressure screening event at a senior center. What level of prevention is this?", options: ["Primary prevention", "Secondary prevention", "Tertiary prevention", "Quaternary prevention"], correct: 1, rationale: "Blood pressure screening is secondary prevention: it detects an existing condition (hypertension) early, before complications develop, allowing prompt treatment." }, { question: "A patient says, 'I know I should quit smoking but I'm not ready yet.' What stage of change is this?", options: ["Precontemplation", "Contemplation", "Preparation", "Action"], correct: 1, rationale: "The contemplation stage is characterized by awareness of the problem and consideration of change, but no commitment to take action yet. The person acknowledges the need to change but is ambivalent." }] };

const environmentalHealth: LessonContent = { title: "Environmental Health Nursing", cellular: { title: "Environmental Health Hazards", content: "Environmental health examines how physical, chemical, biological, and social environmental factors affect human health. Environmental hazards are responsible for approximately 25% of the global disease burden. Physical hazards include radiation (ionizing and non-ionizing), noise, extreme temperatures, and natural disasters. Chemical hazards include air pollution (particulate matter, ozone, nitrogen dioxide), water contamination (lead, arsenic, pesticides, pharmaceuticals), soil contamination (heavy metals, industrial waste), and occupational chemical exposures. Biological hazards include vector-borne diseases (mosquitoes: malaria, dengue, Zika; ticks: Lyme disease, Rocky Mountain spotted fever), waterborne pathogens (Cryptosporidium, Giardia, Legionella), and mold. Social/built environment factors include housing quality, food deserts, transportation access, urban planning, and neighborhood safety. Lead poisoning remains a significant public health concern, especially in children living in older housing with lead-based paint. Lead exposure causes neurological damage (cognitive deficits, behavioral problems), anemia, and renal dysfunction. Blood lead levels ≥3.5 mcg/dL (CDC reference value) require public health follow-up." },
  signs: { left: ["Air quality index (AQI) monitoring for vulnerable populations", "Lead screening in children living in pre-1978 housing", "Water quality testing: bacterial contamination, lead, chemical pollutants", "Occupational health assessment: workplace exposure evaluation", "Vector-borne disease surveillance: tick and mosquito monitoring"], right: ["Childhood lead poisoning: cognitive deficits, behavioral problems, anemia", "Asthma exacerbations from air pollution and indoor allergens", "Waterborne illness outbreaks from contaminated water systems", "Heat-related illness and death during extreme heat events", "Cancer clusters near industrial contamination sites"] },
  medications: [{ name: "Succimer (Chemet)", type: "Chelating agent", action: "Binds lead in the blood allowing renal excretion", sideEffects: "GI upset, rash, elevated liver enzymes, neutropenia", contra: "Allergy to succimer, active hepatitis", pearl: "Used for blood lead levels ≥45 mcg/dL in children; oral administration; source of lead must be identified and removed simultaneously" }],
  pearls: ["Lead poisoning: screen children in pre-1978 housing; blood lead ≥3.5 mcg/dL requires investigation and follow-up", "Radon: second leading cause of lung cancer after smoking — test all homes below the third floor", "Air pollution disproportionately affects children, elderly, and those with respiratory disease", "Food safety: proper cooking temperatures, hand hygiene, cross-contamination prevention, cold chain maintenance", "Environmental justice: low-income and minority communities bear disproportionate environmental health burdens", "Occupational health: right-to-know laws require employers to inform workers of chemical hazards (MSDS/SDS)", "Climate change increases heat-related illness, vector-borne disease range, air pollution, and natural disaster frequency"],
  quiz: [{ question: "A public health nurse is evaluating a neighborhood with homes built in 1965. What environmental health concern should be assessed?", options: ["Radon only", "Lead-based paint exposure, especially for children", "Mold only", "No concerns in homes of this age"], correct: 1, rationale: "Homes built before 1978 may contain lead-based paint, which is the most common source of childhood lead exposure. As paint deteriorates, children may ingest lead dust or paint chips, causing neurotoxicity." }, { question: "What is the CDC reference blood lead level requiring public health action in children?", options: ["10 mcg/dL", "5 mcg/dL", "3.5 mcg/dL", "15 mcg/dL"], correct: 2, rationale: "The CDC updated the blood lead reference value to 3.5 mcg/dL (2021), based on the 97.5th percentile of blood lead levels in U.S. children ages 1-5. Children at or above this level require public health follow-up, environmental investigation, and developmental monitoring." }] };

const disasterPreparedness: LessonContent = { title: "Disaster Preparedness and Response", cellular: { title: "Disaster Nursing and Emergency Management", content: "Disaster preparedness is the planning, training, and resource allocation required to respond effectively to natural and man-made disasters. The disaster management cycle includes four phases: Mitigation (reducing the impact of future disasters through planning, infrastructure improvement, and risk reduction), Preparedness (planning, training, stockpiling supplies, and conducting drills), Response (immediate actions during and after the disaster: search and rescue, triage, emergency medical care, shelter, and resource coordination), and Recovery (long-term restoration of the community including physical, psychological, economic, and social recovery). Mass casualty triage systems prioritize care when resources are overwhelmed. The START (Simple Triage and Rapid Treatment) system uses a 60-second assessment to classify victims: Green/Minor (walking wounded, delayed treatment), Yellow/Delayed (significant injuries but can wait for treatment), Red/Immediate (life-threatening injuries requiring immediate treatment), and Black/Expectant (deceased or injuries incompatible with survival given available resources). Nurses must be prepared for biological threats (anthrax, smallpox, plague, botulism), chemical incidents (nerve agents, industrial chemicals), radiological events (dirty bombs, nuclear accidents), and natural disasters (hurricanes, earthquakes, floods, pandemics)." },
  signs: { left: ["Disaster cycle: Mitigation → Preparedness → Response → Recovery", "START triage: Green (minor), Yellow (delayed), Red (immediate), Black (expectant)", "Incident Command System (ICS): standardized emergency management structure", "Personal preparedness: 72-hour kit, family communication plan, evacuation routes", "Community risk assessment: identify hazards, vulnerabilities, and resources"], right: ["Mass casualties overwhelming available resources", "Infrastructure failure: power, water, communication, transportation", "Psychological trauma: PTSD, acute stress disorder, grief in survivors and responders", "Secondary hazards: contaminated water, disease outbreaks, structural collapse", "Resource allocation ethics: utilitarian approach in mass casualty situations"] },
  medications: [{ name: "Potassium Iodide (KI)", type: "Thyroid blocking agent", action: "Saturates the thyroid gland with stable iodine, preventing uptake of radioactive iodine (I-131)", sideEffects: "GI upset, metallic taste, allergic reactions (iodine allergy)", contra: "Iodine allergy, thyroid disease (relative)", pearl: "Distributed within hours of nuclear/radiological event; most effective if given before or immediately after exposure; protects thyroid only — not total body radiation protection" }, { name: "Atropine + Pralidoxime (Mark I kit)", type: "Nerve agent antidote", action: "Atropine blocks acetylcholine at muscarinic receptors; pralidoxime reactivates cholinesterase", sideEffects: "Tachycardia, dry mouth (atropine); hypertension (pralidoxime)", contra: "None absolute in nerve agent exposure", pearl: "Nerve agent symptoms (SLUDGE/BBB): Salivation, Lacrimation, Urination, Defecation, GI distress, Emesis / Bradycardia, Bronchorrhea, Bronchospasm — give atropine until secretions dry" }],
  pearls: ["START triage: can they walk? (Green). Are they breathing? (if not, open airway — still no = Black). Respiratory rate >30? (Red). Can follow commands? (if not = Red). Otherwise = Yellow", "In mass casualty: think UTILITARIAN — greatest good for the greatest number", "Triage is NOT first come first served — most urgent survivable injuries treated first", "Psychological first aid: safety, calming, self-efficacy, social connection, hope — NOT debriefing", "CBRNE: Chemical, Biological, Radiological, Nuclear, Explosive — know basic responses for each", "Decontamination before treatment for chemical/radiological exposure — to protect healthcare workers", "Nurses must practice self-care: you cannot help others if you are a casualty — personal safety first"],
  quiz: [{ question: "During a mass casualty incident, a victim is not breathing after opening the airway. What START triage category is assigned?", options: ["Green: minor", "Yellow: delayed", "Red: immediate", "Black: expectant"], correct: 3, rationale: "In START triage, if the victim is not breathing even after opening the airway, they are classified as Black (expectant/deceased). In a mass casualty situation with limited resources, resuscitation efforts that would consume significant resources for one patient are not performed when many others need care." }, { question: "A chemical spill has occurred and contaminated victims are arriving at the emergency department. What is the first priority?", options: ["Begin IV fluid resuscitation", "Decontaminate victims before they enter the facility", "Triage and treat in the emergency department", "Administer antidotes immediately"], correct: 1, rationale: "Decontamination of chemically contaminated victims MUST occur before they enter the healthcare facility to protect staff and other patients from secondary contamination. Decontamination tents or showers should be set up outside the facility." }] };

const socialDeterminants: LessonContent = { title: "Social Determinants of Health", cellular: { title: "Upstream Factors Affecting Health Outcomes", content: "Social determinants of health (SDOH) are the conditions in which people are born, grow, live, work, and age that shape health outcomes. These factors account for approximately 30-55% of health outcomes, far exceeding the contribution of medical care (10-20%). The five key domains identified by Healthy People include: Economic Stability (employment, income, food security, housing stability), Education Access and Quality (early childhood education, literacy, vocational training), Health Care Access and Quality (insurance coverage, provider availability, health literacy, cultural competence), Neighborhood and Built Environment (housing quality, transportation, safety, water/air quality, access to healthy foods), and Social and Community Context (social support, community engagement, civic participation, discrimination, incarceration). Health equity means that everyone has a fair and just opportunity to be as healthy as possible, which requires removing obstacles to health such as poverty, discrimination, and their consequences. Health disparities are preventable differences in health outcomes experienced by disadvantaged populations. Nurses must screen for SDOH using validated tools, connect patients to community resources, advocate for policy changes, and address the root causes of health inequities." },
  signs: { left: ["Economic stability: employment, income adequacy, food security, housing stability", "Education: literacy, health literacy, educational attainment", "Healthcare access: insurance, provider availability, transportation to appointments", "Neighborhood: housing quality, safety, food access, environmental quality", "Social context: social support, community engagement, discrimination, isolation"], right: ["Health disparities between racial, ethnic, socioeconomic, and geographic groups", "Food insecurity contributing to malnutrition, obesity, and chronic disease", "Housing instability and homelessness increasing disease exposure and stress", "Health literacy gaps leading to medication errors, missed appointments, poor outcomes", "Social isolation increasing mortality risk equivalent to smoking 15 cigarettes/day"] },
  medications: [],
  pearls: ["SDOH account for 30-55% of health outcomes — more than medical care (10-20%)", "Screen ALL patients for SDOH: food insecurity, housing instability, transportation barriers, safety", "The PRAPARE tool and AHC HRSN screening are validated SDOH screening instruments", "Food insecurity affects 1 in 8 Americans — ask: 'In the past year, were you worried about running out of food?'", "Health literacy: use plain language, teach-back method, visual aids — 36% of U.S. adults have limited health literacy", "Upstream interventions (policy, environment changes) are more effective than downstream (treating individual disease)", "Nurses are mandatory reporters of child and elder abuse — a critical SDOH intersection", "Connect patients to community resources: 211 hotline, food banks, housing assistance, transportation services"],
  quiz: [{ question: "Which factor has the GREATEST influence on health outcomes?", options: ["Quality of medical care received", "Genetic predisposition", "Social and economic conditions (social determinants)", "Individual health behaviors alone"], correct: 2, rationale: "Social determinants of health (income, education, housing, food access, social support) account for 30-55% of health outcomes, far exceeding the contribution of medical care (10-20%) or genetics (20-30%)." }, { question: "A patient repeatedly misses clinic appointments. Upon screening, the nurse discovers the patient lacks transportation. What is the most appropriate nursing action?", options: ["Document non-compliance", "Refer to community transportation services and explore telehealth options", "Discharge the patient from the practice", "Tell the patient to take a taxi"], correct: 1, rationale: "Transportation is a social determinant of health. The nurse should address the barrier by connecting the patient with community resources (medical transportation services, ride programs) and exploring alternatives like telehealth." }] };

const populationHealthAssessment: LessonContent = { title: "Population Health Assessment", cellular: { title: "Community Health Assessment Methods", content: "Population health assessment is the systematic collection, analysis, and interpretation of data about the health status of a defined population to identify health needs, prioritize problems, and plan interventions. The community health assessment process involves: defining the community (geographic area, demographic characteristics), collecting and analyzing data (vital statistics, morbidity/mortality data, demographic data, environmental data, healthcare resource inventory, community input), identifying health priorities (using data analysis and community engagement), developing community health improvement plans, and evaluating outcomes. Data sources include census data, vital records (birth and death certificates), reportable disease surveillance data, hospital discharge data, behavioral risk factor surveys, and community health surveys. The windshield survey is a systematic observation technique where the nurse drives or walks through a community to assess physical characteristics (housing conditions, infrastructure, recreational facilities, commercial areas, environmental hazards, public transportation, healthcare facilities, schools, religious institutions). Community forums, key informant interviews, and focus groups capture community perspectives and priorities. Healthy People provides national health objectives and benchmarks for community health improvement." },
  signs: { left: ["Windshield survey: systematic observation of community characteristics", "Vital statistics analysis: birth rates, death rates, leading causes of death", "Demographic analysis: age distribution, racial/ethnic composition, income levels", "Healthcare resource inventory: hospitals, clinics, providers, pharmacies, mental health services", "Community input: surveys, focus groups, town halls, key informant interviews"], right: ["Health disparities identified between subpopulations", "Gaps in healthcare access or services", "Environmental hazards affecting community health", "Social determinants creating barriers to health", "Emerging health threats requiring intervention"] },
  medications: [],
  pearls: ["Community health assessment is the FOUNDATION of public health practice — assess before you intervene", "Windshield survey: first-hand observation of housing, transportation, infrastructure, safety, resources, environment", "Use MULTIPLE data sources: quantitative (vital statistics, surveys) AND qualitative (focus groups, interviews)", "Community engagement is essential: the community defines its own health priorities", "Health needs assessment vs. health assets assessment: identify BOTH problems AND strengths", "Prioritize health problems using criteria: magnitude, severity, feasibility of intervention, community concern", "Community health improvement plans should include measurable objectives, timelines, and evaluation metrics", "Cultural humility in assessment: approach each community as unique, avoid assumptions based on demographics"],
  quiz: [{ question: "A public health nurse drives through a community and observes deteriorating housing, few grocery stores, limited public transportation, and a lack of recreational facilities. What is this assessment method called?", options: ["Epidemiological survey", "Windshield survey", "Morbidity analysis", "Census data review"], correct: 1, rationale: "A windshield survey is a systematic observation of community characteristics conducted by driving or walking through the community. It provides first-hand data about the physical environment, infrastructure, resources, and conditions." }, { question: "Which data source would provide the leading causes of death in a community?", options: ["Windshield survey", "Vital statistics (death certificates)", "Community focus groups", "Hospital satisfaction surveys"], correct: 1, rationale: "Vital statistics, specifically death certificate data, provide objective information about the leading causes of death in a community. This quantitative data is a cornerstone of community health assessment." }] };

const healthPolicy: LessonContent = { title: "Health Policy and Advocacy", cellular: { title: "Policy Impact on Population Health", content: "Health policy encompasses the laws, regulations, guidelines, and decisions that influence the organization, financing, and delivery of healthcare services and public health interventions. Policy shapes the social, economic, and physical environments that determine health outcomes. At the population level, policy interventions can achieve health improvements that individual clinical interventions cannot. Examples include tobacco control policies (clean indoor air laws, tobacco taxes, advertising bans — which reduced U.S. smoking rates from 42% in 1965 to 12% in 2020), seat belt laws, food safety regulations, water fluoridation, and the Affordable Care Act expanding insurance coverage. The policy process involves: agenda setting (identifying problems that require policy attention), policy formulation (developing solutions), adoption (legislative or regulatory approval), implementation (putting the policy into practice), and evaluation (assessing effectiveness). Nurses, as the largest healthcare workforce and the most trusted profession, have enormous potential to influence health policy through advocacy, coalition building, public testimony, political participation, and professional organization involvement." },
  signs: { left: ["Federal policies: ACA, Medicare, Medicaid, CDC funding, FDA regulation", "State policies: Medicaid expansion, nurse practice acts, scope of practice, public health budgets", "Local policies: building codes, restaurant inspections, school health programs, zoning", "Regulatory policies: OSHA workplace safety, EPA environmental protection, FDA drug safety", "Professional advocacy: testifying, lobbying, coalition building, public education"], right: ["Health disparities perpetuated by inequitable policies", "Underfunding of public health infrastructure", "Restrictive scope of practice laws limiting nurse autonomy", "Barriers to healthcare access from policy gaps", "Unintended consequences of well-intentioned policies"] },
  medications: [],
  pearls: ["Nurses are the MOST trusted profession: our advocacy carries enormous credibility", "Tobacco control policies are the most successful public health policy intervention in history", "Policy change creates systemic, population-level impact that individual interventions cannot achieve", "Know your legislators: build relationships, share patient stories, provide data to support advocacy positions", "ANA Code of Ethics: nurses have a responsibility to advocate for health policy at local, state, and national levels", "Evidence-based policy: use data and research to support policy recommendations", "Health in All Policies (HiAP): integrate health considerations into all sectors (housing, transportation, education)", "Disparities will not be eliminated without policy changes addressing the root causes of inequity"],
  quiz: [{ question: "Which public health policy intervention has had the greatest impact on reducing smoking rates in the United States?", options: ["Individual smoking cessation counseling", "Comprehensive tobacco control policies (taxes, clean air laws, advertising bans)", "Prescription nicotine replacement therapy", "School-based education programs alone"], correct: 1, rationale: "Comprehensive tobacco control policies including tobacco taxes, clean indoor air laws, advertising restrictions, and graphic warning labels have collectively reduced U.S. smoking rates from 42% in 1965 to approximately 12% today — the most successful public health policy achievement." }, { question: "How can nurses most effectively influence health policy?", options: ["By avoiding politics entirely", "Through advocacy, testimony, coalition building, and using their trusted voice to educate legislators and the public", "By focusing solely on bedside care", "By criticizing existing policies on social media"], correct: 1, rationale: "Nurses can influence policy through professional advocacy, testifying before legislative bodies, building coalitions, participating in professional organizations, educating the public, and sharing patient stories with legislators." }] };

const tuberculosisManagement: LessonContent = { title: "Tuberculosis Prevention and Management", cellular: { title: "TB Pathophysiology and Public Health Management", content: "Tuberculosis (TB) is caused by Mycobacterium tuberculosis, an acid-fast bacillus transmitted via airborne droplet nuclei produced when a person with active pulmonary TB coughs, sneezes, speaks, or sings. The small size of droplet nuclei (<5 microns) allows them to remain suspended in air for hours and penetrate deep into the alveoli. Upon inhalation, M. tuberculosis is engulfed by alveolar macrophages but resists intracellular killing due to its waxy mycolic acid cell wall. The bacteria replicate within macrophages, and the immune system forms granulomas (tubercles) to wall off the infection. In most immunocompetent individuals (90-95%), the immune system contains the infection as latent TB infection (LTBI): the person is infected (positive skin test or IGRA) but not contagious and has no symptoms. LTBI can reactivate to active TB disease years or decades later, especially with immunosuppression (HIV, TNF-alpha inhibitors, malnutrition, diabetes, renal failure, organ transplant). Active pulmonary TB presents with persistent cough (>3 weeks), hemoptysis, night sweats, weight loss, and fever. Public health management includes case finding, contact investigation, directly observed therapy (DOT), and infection control." },
  signs: { left: ["Latent TB (LTBI): positive TST or IGRA, asymptomatic, non-infectious, normal CXR", "Active TB: persistent cough >3 weeks, hemoptysis, night sweats, weight loss, fever", "Diagnosis: sputum acid-fast bacilli (AFB) smear and culture (gold standard), CXR, nucleic acid amplification", "TST (Mantoux/PPD): read at 48-72 hours; ≥5 mm positive for high-risk, ≥10 mm for moderate-risk, ≥15 mm for low-risk", "IGRA (QuantiFERON/T-SPOT): blood test, single visit, no return visit needed, not affected by BCG"], right: ["Multidrug-resistant TB (MDR-TB): resistant to isoniazid AND rifampin", "Extensively drug-resistant TB (XDR-TB): MDR plus resistance to fluoroquinolones and injectables", "Miliary TB: hematogenous spread with diffuse disease", "TB meningitis: highest mortality form of extrapulmonary TB", "Treatment failure from non-adherence — DOT prevents this"] },
  medications: [{ name: "Isoniazid (INH)", type: "Antitubercular", action: "Inhibits mycolic acid synthesis in M. tuberculosis cell wall; bactericidal", sideEffects: "Hepatotoxicity (most serious), peripheral neuropathy, drug interactions (CYP450 inhibitor)", contra: "Active liver disease, prior INH hepatotoxicity", pearl: "Give pyridoxine (B6) to prevent peripheral neuropathy; monthly LFT monitoring; LTBI treatment: 9 months of INH or 3 months of INH+rifapentine (3HP regimen)" }, { name: "Rifampin", type: "Antitubercular", action: "Inhibits bacterial RNA polymerase; bactericidal against M. tuberculosis", sideEffects: "Orange discoloration of body fluids, hepatotoxicity, drug interactions (potent CYP450 inducer)", contra: "Active liver disease, concurrent protease inhibitors", pearl: "Warn patients about ORANGE body fluids (urine, tears, sweat, saliva) — harmless but alarming; interacts with many medications including OCPs (use backup contraception)" }],
  pearls: ["TB is transmitted ONLY via airborne route — requires N95 respirator and negative pressure isolation", "Latent TB is NOT contagious — active pulmonary TB IS contagious", "RIPE therapy for active TB: Rifampin, Isoniazid, Pyrazinamide, Ethambutol x 2 months, then RI x 4 months (total 6 months)", "Directly Observed Therapy (DOT): healthcare worker watches patient take each dose — prevents resistance development", "INH + pyridoxine (B6) always together to prevent peripheral neuropathy", "Rifampin turns body fluids ORANGE — warn patients; also reduces effectiveness of oral contraceptives", "Contact investigation: test all close contacts of active TB cases; treat LTBI to prevent future active disease", "Three consecutive negative sputum AFB smears are required before removing airborne isolation"],
  quiz: [{ question: "A patient has a positive tuberculin skin test (10 mm induration), no symptoms, and a normal chest X-ray. What is the diagnosis?", options: ["Active tuberculosis", "Latent tuberculosis infection (LTBI)", "Multidrug-resistant TB", "Tuberculosis meningitis"], correct: 1, rationale: "A positive TST with no symptoms and a normal CXR indicates latent TB infection (LTBI). The person is infected but not contagious. LTBI should be treated (usually with 9 months of INH) to prevent future reactivation to active disease." }, { question: "Why is Directly Observed Therapy (DOT) critical for TB treatment?", options: ["TB medications must be given by injection", "DOT ensures adherence to the full treatment regimen, preventing development of drug-resistant TB", "TB patients cannot take medications independently", "DOT is only used for hospitalized patients"], correct: 1, rationale: "DOT involves a healthcare worker directly observing the patient take each dose of TB medication. This ensures complete adherence to the 6-9 month regimen, which is essential to cure TB and prevent the emergence of drug-resistant strains." }] };

const maternalChildHealth: LessonContent = { title: "Maternal and Child Health Programs", cellular: { title: "MCH Public Health Framework", content: "Maternal and child health (MCH) is a core area of public health focusing on the health of women of reproductive age, pregnant and postpartum women, infants, children, and adolescents. MCH programs aim to reduce maternal and infant mortality, prevent birth defects and developmental disabilities, promote healthy pregnancy outcomes, and ensure children's health and development. Key MCH programs include: the Special Supplemental Nutrition Program for Women, Infants, and Children (WIC) providing nutrition assistance and education for low-income pregnant/postpartum women, infants, and children up to age 5; Title V Maternal and Child Health Services Block Grant (the oldest federal-state health program); Healthy Start (reducing disparities in infant mortality); Nurse-Family Partnership (home visiting program for first-time, low-income mothers); and Early and Periodic Screening, Diagnostic, and Treatment (EPSDT) under Medicaid for children's preventive services. MCH indicators include infant mortality rate (deaths <1 year per 1,000 live births), neonatal mortality rate (deaths <28 days per 1,000 live births), maternal mortality ratio (maternal deaths per 100,000 live births), preterm birth rate, low birth weight rate, and breastfeeding initiation rates." },
  signs: { left: ["WIC: nutrition assistance for pregnant/postpartum women, infants, and children <5", "Prenatal care access: first trimester entry, adequate visit schedule", "Immunization coverage: childhood vaccination rates", "Breastfeeding support: initiation and duration rates", "Developmental screening: ASQ, M-CHAT, Denver II milestones"], right: ["Infant mortality disparities: Black infants die at 2-3x the rate of White infants", "Maternal mortality crisis: U.S. has the highest maternal mortality of any developed country", "Preterm birth: leading cause of infant death and long-term disability", "Unintended pregnancy: approximately 45% of U.S. pregnancies", "Childhood poverty: strongest predictor of poor child health outcomes"] },
  medications: [],
  pearls: ["Infant mortality rate is a KEY indicator of a nation's overall health status", "U.S. infant mortality: approximately 5.4 per 1,000 live births — worse than most developed nations", "Racial disparities: Black women are 3-4x more likely to die from pregnancy-related causes than White women", "WIC provides nutritious food, nutrition education, and healthcare referrals to 6.2 million participants", "Nurse-Family Partnership: evidence-based home visiting program reduces preterm birth, child abuse, and emergency visits", "Folic acid supplementation (400 mcg/day) BEFORE conception prevents 50-70% of neural tube defects", "Lead screening, developmental screening, and immunizations are cornerstones of child health prevention", "Preconception health: address chronic conditions, substance use, weight, and nutrition BEFORE pregnancy"],
  quiz: [{ question: "Which program provides nutrition assistance to low-income pregnant women, infants, and children up to age 5?", options: ["SNAP (food stamps)", "WIC (Special Supplemental Nutrition Program for Women, Infants, and Children)", "Title V Block Grant", "Medicaid"], correct: 1, rationale: "WIC provides supplemental nutrition (specific food packages), nutrition education, breastfeeding support, and healthcare referrals to low-income pregnant and postpartum women, infants, and children up to age 5." }, { question: "The infant mortality rate in a community is significantly higher among one racial group. What does this represent?", options: ["Natural biological variation", "A health disparity that requires investigation and intervention", "Expected statistical variation", "Measurement error"], correct: 1, rationale: "Significant racial differences in infant mortality represent health disparities — preventable differences in health outcomes driven by social, economic, and environmental inequities. These disparities require targeted public health interventions addressing root causes." }] };

const substanceUsePublicHealth: LessonContent = { title: "Substance Use and Public Health", cellular: { title: "Addiction as a Public Health Crisis", content: "Substance use disorders (SUDs) are chronic, relapsing brain diseases characterized by compulsive drug seeking and use despite harmful consequences. The neurobiological basis involves the mesolimbic dopamine system (reward pathway): drugs of abuse hijack this system, producing supraphysiological dopamine release that reinforces drug-taking behavior. With repeated use, neuroadaptation occurs (tolerance and dependence), the prefrontal cortex (executive function and impulse control) becomes impaired, and the stress/anti-reward systems become hyperactive, driving continued use to avoid withdrawal rather than to achieve euphoria. The opioid crisis is a major public health emergency: overdose deaths exceeded 100,000 annually in the U.S. Harm reduction is an evidence-based public health approach that reduces the negative consequences of substance use without requiring abstinence. Harm reduction strategies include naloxone distribution (opioid reversal), syringe services programs (needle exchange to prevent HIV/hepatitis), medication-assisted treatment (MAT: methadone, buprenorphine, naltrexone), supervised consumption sites, fentanyl test strips, and drug checking services. Harm reduction does NOT enable drug use — it keeps people alive and connected to care until they are ready for treatment." },
  signs: { left: ["Screening tools: CAGE, AUDIT, DAST, SBIRT (Screening, Brief Intervention, Referral to Treatment)", "Harm reduction: naloxone kits, syringe exchange, MAT, fentanyl test strips", "Medication-assisted treatment: methadone, buprenorphine/naloxone, naltrexone", "Recovery support: peer support specialists, mutual aid groups, housing programs", "Neonatal abstinence syndrome (NAS): withdrawal in newborns exposed to opioids in utero"], right: ["Opioid overdose: respiratory depression, miosis, unresponsiveness — naloxone saves lives", "Fentanyl contamination: illicitly manufactured fentanyl is 50-100x more potent than morphine", "HIV and hepatitis C transmission from shared injection equipment", "Alcohol withdrawal: can be FATAL — seizures, delirium tremens require medical management", "Stigma: the greatest barrier to treatment seeking and recovery"] },
  medications: [{ name: "Naloxone (Narcan)", type: "Opioid antagonist", action: "Competitively displaces opioids from mu-receptors, reversing respiratory depression", sideEffects: "Acute withdrawal symptoms (NOT dangerous but uncomfortable), agitation, nausea", contra: "NO absolute contraindications in suspected overdose", pearl: "Intranasal 4 mg or IM 0.4 mg; effects last 30-90 minutes (shorter than most opioids); may need repeat doses; ALWAYS call 911 after administering — patient may re-seduce when naloxone wears off" }, { name: "Buprenorphine/Naloxone (Suboxone)", type: "Partial opioid agonist/antagonist", action: "Buprenorphine partially activates mu-receptors (reducing cravings without full euphoria); naloxone deters injection", sideEffects: "Headache, nausea, constipation, precipitated withdrawal if given too early", contra: "Should not be initiated until patient is in mild-moderate withdrawal (COWS score ≥8)", pearl: "Can be prescribed in office settings (unlike methadone); reduces overdose deaths by 50% compared to no medication treatment; safe in pregnancy" }],
  pearls: ["Addiction is a BRAIN DISEASE, not a moral failing — reduce stigma by using person-first language", "Use 'person with substance use disorder' NOT 'addict,' 'junkie,' or 'substance abuser'", "Harm reduction saves lives: naloxone distribution has reversed hundreds of thousands of overdoses", "Good Samaritan laws protect bystanders who call 911 for overdose from drug charges (most states)", "SBIRT: universal screening in healthcare settings identifies at-risk individuals before crisis", "Alcohol withdrawal can be FATAL: seizures and delirium tremens require medical management; opioid withdrawal is uncomfortable but rarely fatal", "Medication-assisted treatment (MAT) is the gold standard for opioid use disorder — it is treatment, not 'trading one addiction for another'", "Stigma is the #1 barrier to treatment: treat SUDs with the same compassion as any other chronic disease"],
  quiz: [{ question: "A community health nurse is distributing naloxone kits. A colleague asks why they are 'enabling drug use.' What is the best response?", options: ["Agree and stop the program", "Explain that harm reduction reduces death while maintaining connection to treatment — it does not enable use", "Say it's just a policy requirement", "Defer to administration"], correct: 1, rationale: "Harm reduction is an evidence-based public health approach that reduces death and disease from substance use while keeping people connected to care and treatment. Naloxone reverses overdose and saves lives. It does not enable or encourage drug use." }, { question: "Why is the term 'addict' considered harmful in public health practice?", options: ["It is medically accurate", "It perpetuates stigma that discourages treatment seeking — person-first language is preferred", "It is only harmful in clinical settings", "There is no concern with this term"], correct: 1, rationale: "Stigmatizing language like 'addict' or 'junkie' reduces the person to their disease, perpetuating shame and discouraging treatment seeking. Person-first language ('person with substance use disorder') acknowledges the disease while respecting the person's dignity." }] };

const mentalHealthPublic: LessonContent = { title: "Mental Health in Public Health", cellular: { title: "Population Mental Health", content: "Mental health is integral to overall health and is a major public health concern. Mental disorders affect approximately 1 in 5 adults annually and are a leading cause of disability worldwide. Depression alone is the leading cause of disability globally. Suicide is the 10th leading cause of death in the U.S. and the 2nd leading cause among ages 10-34. Public health approaches to mental health include: population-level screening (PHQ-9 for depression, GAD-7 for anxiety, Columbia Suicide Severity Rating Scale), reducing stigma through education and advocacy, expanding access to mental health services (integration into primary care, telehealth, school-based services, community mental health centers), crisis intervention (988 Suicide and Crisis Lifeline, crisis stabilization units, mobile crisis teams), and addressing social determinants that contribute to mental illness (poverty, trauma, discrimination, social isolation). Mental Health First Aid training teaches community members to recognize and respond to mental health crises. Adverse Childhood Experiences (ACEs) are traumatic events in childhood (abuse, neglect, household dysfunction) that increase lifetime risk of mental illness, substance use, chronic disease, and early death in a dose-response relationship." },
  signs: { left: ["PHQ-9 screening: score ≥10 suggests moderate depression", "GAD-7 screening: score ≥10 suggests moderate anxiety", "Columbia Suicide Severity Rating Scale: structured suicide risk assessment", "ACEs screening: Adverse Childhood Experiences questionnaire", "Mental Health First Aid: ALGEE — Assess, Listen, Give reassurance, Encourage professional help, Encourage self-help"], right: ["Suicide risk: previous attempt, plan, access to means, hopelessness, substance use, isolation", "Treatment gap: only ~50% of people with mental illness receive any treatment", "Stigma: major barrier to seeking mental health care", "Crisis presentations: suicidal ideation, psychosis, acute agitation, panic attacks", "Trauma-informed care: understanding that trauma is widespread and affects health behaviors"] },
  medications: [],
  pearls: ["Ask about suicide directly: 'Are you thinking about killing yourself?' — asking does NOT increase risk", "988 Suicide and Crisis Lifeline: call or text 988 for 24/7 crisis support", "ACEs: 4+ ACEs significantly increase risk for mental illness, substance use, and chronic disease", "Integrate mental health screening into ALL healthcare settings — not just specialty mental health", "Trauma-informed care: ask 'What happened to you?' not 'What's wrong with you?'", "Social isolation increases mortality risk equivalent to smoking 15 cigarettes per day", "Mental Health Parity: federal law requires insurance to cover mental health on par with physical health", "Community mental health centers provide accessible, affordable care for underserved populations"],
  quiz: [{ question: "A patient scores 15 on the PHQ-9. What does this indicate?", options: ["No depression", "Minimal depression", "Moderately severe depression requiring treatment evaluation", "Normal screening result"], correct: 2, rationale: "PHQ-9 scores: 0-4 (minimal), 5-9 (mild), 10-14 (moderate), 15-19 (moderately severe), 20-27 (severe). A score of 15 indicates moderately severe depression and warrants treatment evaluation including potential medication and/or therapy referral." }, { question: "A community health nurse is asked if asking about suicide will 'put the idea in someone's head.' What is the evidence-based response?", options: ["Yes, avoid asking about suicide directly", "No, asking about suicide directly does NOT increase risk — it may actually reduce distress by allowing the person to feel heard", "Only mental health professionals should ask about suicide", "Only ask if the person brings it up first"], correct: 1, rationale: "Research consistently shows that asking about suicide does NOT increase risk or 'plant the idea.' In fact, compassionate, direct questioning about suicidal thoughts can reduce distress and connect people to help." }] };

const emergingInfectiousDiseases: LessonContent = { title: "Emerging and Re-Emerging Infectious Diseases", cellular: { title: "Emerging Pathogen Threats", content: "Emerging infectious diseases are infections that have newly appeared in a population or are rapidly increasing in incidence or geographic range. Re-emerging diseases are those that were previously controlled but are now increasing. Factors driving emergence include: urbanization and population growth (increased human-to-human transmission), deforestation and land-use changes (increased human-animal contact and zoonotic spillover events), climate change (expanding vector ranges — mosquitoes carrying dengue, Zika, malaria moving to new latitudes), antimicrobial resistance (rendering treatment ineffective), international travel (rapid global spread), and bioterrorism potential. Recent examples include COVID-19 (SARS-CoV-2), Ebola virus disease, Zika virus, MERS, avian influenza (H5N1, H7N9), mpox (monkeypox), and drug-resistant tuberculosis. Pandemic preparedness requires robust surveillance systems, rapid diagnostic capability, stockpiling of PPE and medications, coordinated international response, vaccine development platforms (mRNA technology), and public communication strategies. The One Health approach recognizes that human, animal, and environmental health are interconnected and that addressing emerging diseases requires interdisciplinary collaboration across these domains." },
  signs: { left: ["Surveillance systems: disease reporting, syndromic surveillance, genomic sequencing", "Outbreak investigation: case definition, case finding, contact tracing, source identification", "Pandemic preparedness: stockpiles, surge capacity, communication plans, vaccine platforms", "One Health approach: human-animal-environment health interconnection", "Travel health: pre-travel vaccinations, risk assessment, post-travel screening"], right: ["Zoonotic spillover events causing novel pandemics", "Antimicrobial resistance creating untreatable infections", "Pandemic overwhelm of healthcare systems", "Misinformation undermining public health response", "Health inequities worsened during pandemics"] },
  medications: [],
  pearls: ["75% of emerging infectious diseases are ZOONOTIC — originating in animal populations", "Climate change is expanding the range of vector-borne diseases to new geographic areas", "mRNA vaccine technology (developed for COVID-19) can be rapidly adapted for new pathogens", "Antimicrobial resistance is an 'antibiotic apocalypse' — the WHO's top 10 global health threats", "Pandemic preparedness: 'It's not if, but when' — invest in surveillance, stockpiles, and rapid response", "One Health: human, animal, and environmental health are interconnected — collaboration is essential", "Contact tracing remains a cornerstone of outbreak response: identify, notify, monitor, and support contacts", "Health communication must be clear, consistent, culturally appropriate, and combat misinformation"],
  quiz: [{ question: "What percentage of emerging infectious diseases originate from animal populations (zoonotic)?", options: ["25%", "50%", "75%", "90%"], correct: 2, rationale: "Approximately 75% of emerging infectious diseases are zoonotic, originating from animal populations and crossing the species barrier to infect humans. This underscores the importance of the One Health approach." }, { question: "Which factor is NOT driving the emergence of new infectious diseases?", options: ["Deforestation and urbanization", "Climate change expanding vector ranges", "Improved global sanitation systems", "International travel enabling rapid spread"], correct: 2, rationale: "Improved sanitation actually REDUCES infectious disease risk. The factors driving emergence include deforestation (increased human-animal contact), climate change (expanding vector habitats), international travel (rapid global spread), and antimicrobial resistance." }] };

